        return resolved as? eACTION_METHOD__PURPOSE__provider
      }

      //PARTIAL COMPLEX ENTITY SUPPORT - to fill up the explicit attribute values with the baseComplex's redeclared derived attribute value so that the partial complex entities constructed from the baseComplex can provide the consistent attribute values
      final public override class func fixupPartialComplexEntityAttributes(partialComplex: SDAI.ComplexEntity, baseComplex: SDAI.ComplexEntity) {
        guard let pe = partialComplex.partialEntityInstance(eACTION_METHOD.PartialEntity.self) else { return }

        if pe._purpose == nil, self._purpose__provider(complex: partialComplex) == nil, 
          let base__purpose__provider = self._purpose__provider(complex: baseComplex) {
          pe._purpose = base__purpose__provider._purpose__getter(complex: baseComplex)
        }
      }
