      //VALUE COMPARISON SUPPORT
      public override func hashAsValue(into hasher: inout Hasher, visited complexEntities: inout Set<SDAI.ComplexEntity>) {
        super.hashAsValue(into: &hasher, visited: &complexEntities)
        self._name.value.hashAsValue(into: &hasher, visited: &complexEntities)
        self._description?.value.hashAsValue(into: &hasher, visited: &complexEntities)
        self._consequence.value.hashAsValue(into: &hasher, visited: &complexEntities)
        self._purpose?.value.hashAsValue(into: &hasher, visited: &complexEntities)
      }

      public override func isValueEqual(to rhs: SDAI.PartialEntity, visited comppairs: inout Set<SDAI.ComplexPair>) -> Bool {
        guard let rhs = rhs as? Self else { return false }
        if !super.isValueEqual(to: rhs, visited: &comppairs) { return false }
        if let comp = self._name.value.isValueEqualOptionally(to: rhs._name.value, visited: &comppairs)	{
          if !comp { return false }
        }
        else { return false }
        if let comp = self._description?.value.isValueEqualOptionally(to: rhs._description?.value, visited: &comppairs)	{
          if !comp { return false }
        }
        else { return false }
        if let comp = self._consequence.value.isValueEqualOptionally(to: rhs._consequence.value, visited: &comppairs)	{
          if !comp { return false }
        }
        else { return false }
        if let comp = self._purpose?.value.isValueEqualOptionally(to: rhs._purpose?.value, visited: &comppairs)	{
          if !comp { return false }
        }
        else { return false }
        return true
      }

      public override func isValueEqualOptionally(to rhs: SDAI.PartialEntity, visited comppairs: inout Set<SDAI.ComplexPair>) -> Bool? {
        guard let rhs = rhs as? Self else { return false }
        var result: Bool? = true
        if let comp = super.isValueEqualOptionally(to: rhs, visited: &comppairs) {
          if !comp { return false }
        }
        else { result = nil }
        if let comp = self._name.value.isValueEqualOptionally(to: rhs._name.value, visited: &comppairs) {
          if !comp { return false }
        }
        else { result = nil }
        if let comp = self._description?.value.isValueEqualOptionally(to: rhs._description?.value, visited: &comppairs) {
          if !comp { return false }
        }
        else { result = nil }
        if let comp = self._consequence.value.isValueEqualOptionally(to: rhs._consequence.value, visited: &comppairs) {
          if !comp { return false }
        }
        else { result = nil }
        if let comp = self._purpose?.value.isValueEqualOptionally(to: rhs._purpose?.value, visited: &comppairs) {
          if !comp { return false }
        }
        else { result = nil }
        return result
      }


      //EXPRESS IMPLICIT PARTIAL ENTITY CONSTRUCTOR
      /// initialize from explicit attribute values
      public init(
        NAME: tLABEL, 
        DESCRIPTION: tTEXT? , 
        CONSEQUENCE: tTEXT, 
        PURPOSE: tTEXT? 
      ) {

        self._name = NAME
        self._description = DESCRIPTION
        self._consequence = CONSEQUENCE
        self._purpose = PURPOSE

        super.init(asAbstractSuperclass:())
      }

      //PARTIAL ENTITY COPY CONSTRUCTOR
      /// copy constructor
      public required convenience init(from original:SDAI.PartialEntity) {
        let original = original as! Self
        self.init( NAME: original._name, DESCRIPTION: original._description, CONSEQUENCE: original._consequence, PURPOSE: original._purpose )
      }

      //p21 PARTIAL ENTITY CONSTRUCTOR
      /// initialize from ISO 10303-21 exchange structure parameters
      public required convenience init?(
        parameters: [P21Decode.ExchangeStructure.Parameter],
        exchangeStructure: P21Decode.ExchangeStructure
      ) {
        let numParams = 4
        guard parameters.count == numParams
        else { exchangeStructure.error = "number of p21 parameters(\(parameters.count)) are different from expected(\(numParams)) for partial entity(\(Self.entityName)) constructor"; return nil }

        guard case .success(let p0) = exchangeStructure.recoverRequiredParameter(as: tLABEL.self, from: parameters[0])
        else { exchangeStructure.add(errorContext: "while recovering parameter [0]NAME for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p1) = exchangeStructure.recoverOptionalParameter(as: tTEXT.self, from: parameters[1])
        else { exchangeStructure.add(errorContext: "while recovering parameter [1]DESCRIPTION for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p2) = exchangeStructure.recoverRequiredParameter(as: tTEXT.self, from: parameters[2])
        else { exchangeStructure.add(errorContext: "while recovering parameter [2]CONSEQUENCE for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p3) = exchangeStructure.recoverOmittableParameter(as: tTEXT.self, from: parameters[3])
        else { exchangeStructure.add(errorContext: "while recovering parameter [3]PURPOSE for partial entity(\(Self.entityName)) constructor"); return nil }

        self.init( NAME: p0, DESCRIPTION: p1, CONSEQUENCE: p2, PURPOSE: p3 )
      }
    }
  }
